--- a/src/staking/DelegationManagerLib.sol
+++ b/src/staking/DelegationManagerLib.sol
@@ -854,6 +854,14 @@ function _addBlueprintToDelegation(uint256 delegationIndex, uint64 blueprintId) internal {
         // Only Fixed mode delegations can modify blueprints
         if (d.selectionMode != Types.BlueprintSelectionMode.Fixed) {
             revert DelegationErrors.NotFixedMode();
         }

+        // Block rebalancing if operator has pending slashes
+        // This prevents Fixed-mode delegators from moving stake out of a
+        // blueprint pool that is about to be slashed during the dispute window
+        uint64 pendingSlashes = _operatorPendingSlashCount[d.operator];
+        if (pendingSlashes > 0) {
+            revert DelegationErrors.PendingSlashExists(d.operator, pendingSlashes);
+        }
+
         uint64[] storage blueprints = _delegationBlueprints[msg.sender][delegationIndex];

         // Check if blueprint already selected
@@ -918,6 +926,14 @@ function _removeBlueprintFromDelegation(uint256 delegationIndex, uint64 blueprintId) internal {
         // Only Fixed mode delegations can modify blueprints
         if (d.selectionMode != Types.BlueprintSelectionMode.Fixed) {
             revert DelegationErrors.NotFixedMode();
         }

+        // Block rebalancing if operator has pending slashes
+        // This prevents Fixed-mode delegators from moving stake out of a
+        // blueprint pool that is about to be slashed during the dispute window
+        uint64 pendingSlashes = _operatorPendingSlashCount[d.operator];
+        if (pendingSlashes > 0) {
+            revert DelegationErrors.PendingSlashExists(d.operator, pendingSlashes);
+        }
+
         uint64[] storage blueprints = _delegationBlueprints[msg.sender][delegationIndex];

